function Dashboard() {

    const logout = () => {
        localStorage.removeItem("token");
        alert("Logout Successful");
    }

    return (
        <div className="container">

            <h2>Student Dashboard</h2>

            <p font-size ="20px ">Welcome to Scholarship Portal</p>

            <button onClick={logout}>
                Logout
            </button>

        </div>
    )
}


export default Dashboard;
